.bt-form-field {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
}

.bt-form-field__label {
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  color: var(--text-primary);
}

.bt-form-field__label-required {
  color: var(--color-ext-error-bold);
  margin-inline-start: 2px;
}

.bt-form-field__helper {
  font-size: var(--typography-font-size-xs);
  color: var(--text-secondary);
  line-height: var(--typography-line-height-xs);
}

.bt-form-field__error {
  font-size: var(--typography-font-size-xs);
  color: var(--color-ext-error-bold);
  line-height: var(--typography-line-height-xs);
}

export interface BTFormFieldProps {
  /** Label text shown above the input slot. */
  label: string;
  /** Shows a red * after the label. @default false */
  required?: boolean;
  /** Helper text shown below the slot. Hidden when error is present. */
  helper?: string;
  /** Error message from outside (server error, parent validation). Shown below slot. */
  error?: string | null;
  /**
   * ID forwarded to the slot input's id attribute via provide/inject.
   * Auto-generated (bt-field-<uid>) when omitted.
   */
  id?: string;
}
